import React, { useState } from 'react';
import API from '../services/api';

export default function TrackJob(){
  const [jobId,setJobId]=useState('');
  const [job,setJob]=useState(null);

  async function fetchJob(e){
    e.preventDefault();
    try{
      const res = await API.get('/jobs/' + jobId);
      setJob(res.data);
    }catch(e){ alert('Not found'); }
  }

  return (
    <div style={{padding:20}}>
      <h2>Track Job</h2>
      <form onSubmit={fetchJob}>
        <input placeholder='Job ID' value={jobId} onChange={e=>setJobId(e.target.value)} /><button>Track</button>
      </form>
      {job && (
        <div style={{marginTop:20}}>
          <h3>Job {job._id}</h3>
          <p>Status: {job.status}</p>
          <p>Complaint: {job.complaint}</p>
          <p>Parts used: {job.partsUsed?.length || 0}</p>
          <a href={job.invoice?.filePath} target='_blank' rel='noreferrer'>Download Invoice</a>
        </div>
      )}
    </div>
  );
}
